/**
 * Generated by `createschema ticket.TicketFile 'organization:Text;file?:File;ticket?:Relationship:Ticket:SET_NULL;'`
 */

import { useCreateTicketFileMutation, CreateTicketFileMutation } from '@app/condo/gql'
import {
    TicketFile,
    TicketFileCreateInput,
    TicketFileUpdateInput,
    QueryAllTicketFilesArgs,
} from '@app/condo/schema'
import { UploadFile } from 'antd/lib/upload/interface'
import getConfig from 'next/config'

import { generateReactHooks } from '@open-condo/codegen/generate.hooks'
import { upload as uploadFiles, buildMeta } from '@open-condo/files'
import { getClientSideSenderInfo } from '@open-condo/miniapp-utils/helpers/sender'
import { useAuth } from '@open-condo/next/auth'
import { useOrganization } from '@open-condo/next/organization'

import { TicketFile as TicketFileGQL } from '@condo/domains/ticket/gql'

const {
    useObject,
    useObjects,
    useUpdate,
    useSoftDelete,
} = generateReactHooks<TicketFile, TicketFileCreateInput, TicketFileUpdateInput, QueryAllTicketFilesArgs>(TicketFileGQL)

const { publicRuntimeConfig: { fileClientId, condoDomain } = {} } = getConfig()

type FileInputType = File | UploadFile | { signature: string, originalFilename: string, mimetype: string }
type CreatedTicketFile = NonNullable<CreateTicketFileMutation['ticketFile']>

const useCreate = (attrs?: Partial<TicketFileCreateInput>, onComplete?: (result?: CreatedTicketFile) => Promise<void> | void) => {
    const [mutate] = useCreateTicketFileMutation()
    const { user } = useAuth()
    const { organization } = useOrganization()

    return async (data: Partial<TicketFileCreateInput>): Promise<CreatedTicketFile | undefined> => {
        const sender = getClientSideSenderInfo()
        try {
            let fileField = data.file as FileInputType | undefined

            if (fileClientId && user?.id && fileField && !('signature' in fileField)) {
                const maybeFile = (fileField as UploadFile)?.originFileObj || fileField
                if (maybeFile && 'name' in maybeFile && 'type' in maybeFile) {
                    const uploadResult = await uploadFiles({
                        serverUrl: condoDomain,
                        files: [maybeFile as File],
                        meta: buildMeta({
                            userId: user.id,
                            fileClientId,
                            modelNames: ['TicketFile'],
                            fingerprint: sender.fingerprint,
                            organizationId: organization?.id,
                        }),
                    })

                    const signature = uploadResult.files?.[0]?.signature
                    if (signature) {
                        fileField = {
                            signature,
                            originalFilename: maybeFile.name,
                            mimetype: maybeFile.type,
                        }
                    }
                }
            }

            const variablesData = { dv: 1, sender, ...attrs, ...data, file: fileField }
            const res = await mutate({ variables: { data: variablesData } })
            const created = res?.data?.ticketFile
            if (onComplete) await onComplete(created)
            return created
        } catch (err) {
            console.error('TicketFile upload failed', err)
            throw err
        }
    }
}

export {
    useObject,
    useObjects,
    useCreate,
    useUpdate,
    useSoftDelete,
}
